from flask import Flask, redirect, url_for, session, request
import requests
import os
import secrets

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Configuration
AUTHORIZATION_URL = 'https://authorization-server.com/auth'
TOKEN_URL = 'https://authorization-server.com/token'
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'
SCOPE = 'your_scope'

@app.route('/login')
def login():
    state = secrets.token_urlsafe(16)
    session['oauth_state'] = state
    authorization_url = f"{AUTHORIZATION_URL}?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope={SCOPE}&state={state}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    if request.args.get('state') != session.get('oauth_state'):
        return "Invalid state parameter", 400

    code = request.args.get('code')
    token_response = requests.post(TOKEN_URL, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })

    if token_response.status_code == 200:
        token_data = token_response.json()
        session['access_token'] = token_data['access_token']
        return "Access token stored in session"
    else:
        return "Failed to obtain access token", 400

if __name__ == '__main__':
    app.run(debug=True)